#include "cand_conv.h"
#include <math.h>
#include <vector>
namespace ncnn {

Cand_Conv::Cand_Conv()
{
    one_blob_only = false;
    support_inplace = false;
}

int Cand_Conv::load_param(const ParamDict& pd)
{
    num_output = pd.get(0, 0);
    kernel_w = pd.get(1, 0);
    kernel_h = pd.get(11, kernel_w);
    dilation_w = pd.get(2, 1);
    dilation_h = pd.get(12, dilation_w);
    stride_w = pd.get(3, 1);
    stride_h = pd.get(13, stride_w);
    pad_left = pd.get(4, 1);
    pad_right = pd.get(15, pad_left);
    pad_top = pd.get(14, pad_left);
    pad_bottom = pd.get(16, pad_top);
    bias_term = pd.get(5, 1);
    weight_data_size = pd.get(6, 0);
    group = pd.get(7, 1);
    return 0;
}

int Cand_Conv::load_model(const ModelBin& /*mb*/)
{
    return 0;
}

int Cand_Conv::forward(const std::vector<Mat>& bottom_blobs, std::vector<Mat>& top_blobs, const Option& opt) const
{
    const Mat& x = bottom_blobs[0];
    const Mat& w = bottom_blobs[1];

    const int W = x.w;
    const int H = x.h;

    int kw, kh, cin_per_group, Cout;
    if (w.dims == 4)
    {
        kw = w.w;
        kh = w.h;
        cin_per_group = w.d;
        Cout = w.c;
    }
    else if (w.dims == 3)
    {
        kw = w.w;
        kh = w.h;
        Cout = w.c;
        cin_per_group = 1;
    }
    else
    {
        kw = w.w;
        kh = 1;
        Cout = w.h;
        cin_per_group = 1;
    }

    const int g = group;
    const int cout_per_group = Cout / g;

    const int pad_h_t = pad_top;
    const int pad_w_l = pad_left;

    const int kernel_extent_w = dilation_w * (kw - 1) + 1;
    const int kernel_extent_h = dilation_h * (kh - 1) + 1;

    const int outw = (W + pad_left + pad_right - kernel_extent_w) / stride_w + 1;
    const int outh = (H + pad_top + pad_bottom - kernel_extent_h) / stride_h + 1;
    const int outHW = outw * outh;

    Mat& top_blob = top_blobs[0];
    top_blob.create(outw, outh, Cout, (size_t)4u, opt.blob_allocator);
    if (top_blob.empty())
        return -100;

    const bool has_bias = bias_term && bottom_blobs.size() > 2;
    const float* bias_ptr = 0;
    Mat bias_flat;
    if (has_bias)
    {
        bias_flat = bottom_blobs[2];
        bias_ptr = (const float*)bias_flat;
    }

    const int per_oc = cin_per_group * kh * kw; // K dimension of GEMM

    // im2col column buffer per group: [per_oc][outHW]
    // Reused across groups to bound memory.
    std::vector<float> col((size_t)per_oc * outHW);

    // GEMM tiling knobs
    const int MTILE = 1; // rows of weight (output channels) per tile
    const int NTILE = 256; // columns (spatial positions) per tile

    for (int grp = 0; grp < g; grp++)
    {
        const int ic_start = grp * cin_per_group;
        const int oc_start = grp * cout_per_group;

        // ---- im2col: build col[k][n], k over (icl,ky,kx), n over spatial ----
        {
            int krow = 0;
            for (int icl = 0; icl < cin_per_group; icl++)
            {
                const int ic = ic_start + icl;
                const float* xin = x.channel(ic);
                for (int ky = 0; ky < kh; ky++)
                {
                    for (int kx = 0; kx < kw; kx++)
                    {
                        float* crow = &col[(size_t)krow * outHW];
                        int n = 0;
                        for (int oy = 0; oy < outh; oy++)
                        {
                            const int iy = oy * stride_h - pad_h_t + ky * dilation_h;
                            const bool yvalid = (iy >= 0 && iy < H);
                            for (int ox = 0; ox < outw; ox++)
                            {
                                float v = 0.f;
                                if (yvalid)
                                {
                                    const int ix = ox * stride_w - pad_w_l + kx * dilation_w;
                                    if (ix >= 0 && ix < W)
                                        v = xin[iy * W + ix];
                                }
                                crow[n++] = v;
                            }
                        }
                        krow++;
                    }
                }
            }
        }

        // ---- GEMM: out[m][n] = sum_k weight[m][k] * col[k][n] (+bias) ----
        for (int mt = 0; mt < cout_per_group; mt += MTILE)
        {
            const int mend = (mt + MTILE < cout_per_group) ? (mt + MTILE) : cout_per_group;

            for (int nt = 0; nt < outHW; nt += NTILE)
            {
                const int nend = (nt + NTILE < outHW) ? (nt + NTILE) : outHW;

                for (int m = mt; m < mend; m++)
                {
                    const int oc = oc_start + m;
                    float* outptr = top_blob.channel(oc);
                    const float* kptr = w.channel(oc); // [per_oc] contiguous
                    const float b = has_bias ? bias_ptr[oc] : 0.f;

                    for (int n = nt; n < nend; n++)
                        outptr[n] = b;

                    for (int k = 0; k < per_oc; k++)
                    {
                        const float wv = kptr[k];
                        const float* crow = &col[(size_t)k * outHW];
                        #pragma clang loop vectorize(enable)
                        for (int n = nt; n < nend; n++)
                            outptr[n] += wv * crow[n];
                    }
                }
            }
        }
    }

    return 0;
}

DEFINE_LAYER_CREATOR(Cand_Conv)
} // namespace ncnn

